import{copyText}from"components/copy-button/clipboard";function wire(e){const n=e.querySelector(".copy-button__btn"),t=e.querySelector(".copy-button__status");if(!n)return;n.addEventListener("click",()=>{const n=e.dataset.copyValue||"";copyText(n).then(()=>{e.classList.add("copy-button--copied"),t&&(t.textContent="Copied"),setTimeout(()=>{e.classList.remove("copy-button--copied"),t&&(t.textContent="")},1800)})})}document.querySelectorAll(".copy-button").forEach(wire)